import osimport csvimport subprocessimport loggingimport pyodbcfrom builtins import Exceptionlogging.basicConfig(level=logging.DEBUG,                    format='%(asctime)s - %(name)s - %(levelname)s - %(message)s',                    handlers=[                        logging.FileHandler('application.log'),                        logging.StreamHandler()                    ])# Get a logger instancelogger = logging.getLogger(__name__)file_path = '../files/db_restore.csv'data_dict = {}with open(file_path, 'r') as file:    reader = csv.DictReader(file)    for row in reader:        # Assuming the first column contains keys and the second column contains values        key = row['Field']        value = row['Value']        data_dict[key] = value# print(data_dict)def get_db_connection():    """ methods to get the database cursor"""    connection = None    try:        # connection = pyodbc.connect("DRIVER={"+data_dict['DATABASEDRIVER']        #                             + "} SERVER="+data_dict['APPLICATIONSERVER']        #                             + " DATABASE="+data_dict['DATABASENAME']        #                             + " UID="+data_dict['DB_USERNAME']        #                             + " PWD="+data_dict['DB_PASSWORD']        #                             + "")        connection = pyodbc.connect("DRIVER={sql server}"                                    + "; SERVER=dev1"                                    + "; UID=sa"                                    + "; PWD=Nedss123!"                                    + ";",autocommit=True                                    )    except Exception as e:        logger.error(str(e))    return connection# method to execute query and perform DB open and close settingsdef execute_query(query):    query_result = None    conn = None    cur = None    try:        conn = get_db_connection()        cur = conn.cursor()        cur.execute(query)        query_result = cur.fetchall()        for i in query_result:            # print(i)            logger.info("Row : %s", i)        # print("execute_query_results:==>{0}".format(query), "{0}".format(query_result))    except pyodbc.Error as e:        logger.error(str(e))        # pass    finally:        if cur is not None:            cur.close()        if conn is not None:            conn.close()    if query_result != None:        return query_result    else:        return Nonedef command_process(command,Flag):    if Flag == True:        process = subprocess.run(command, capture_output=True, text=True)        return process.stdout    else:        process = subprocess.Popen(command, shell=True, stdout=subprocess.PIPE, stderr=subprocess.PIPE)        stdout, stderr = process.communicate()        # Check for errors        if process.returncode != 0:            print(f"Error: {stderr.decode('utf-8')}")        else:            print(f"Output: {stdout.decode('utf-8')}")def sqlcmd_execute(sqlcommand):    sqlcmd_command = (        'sqlcmd -S {server} -U {username} -P {password} -Q "{query}"'    ).format(        server=data_dict['APPLICATIONSERVER'],        username=data_dict['DB_USERNAME'],        password=data_dict['DB_PASSWORD'],        query=sqlcommand    )    return command_process(sqlcmd_command, False)def restore_db_backup():    # Construct the command    command = ["net", "use", r"\\{}".format(data_dict['DATABASENAME']),               "/user:{}".format(data_dict['SERVER_USERNAME']), data_dict['SERVER_PASSWORD']               ]    command_process(command, True)    command = 'cmd.exe /c dir /b /a-d "{0}"'.format(data_dict['DB_RESTORE_PATH'])    # command = 'cmd.exe /c dir /b /a-d "{0}"'.format(r'C:\TEMP\20211118')    name = command_process(command, True)    arr = name.split(".bak")    for i in arr:        query("USE master")        if "ODSE" in i:            print("Restoring NBS_ODSE")            sqlcmd_execute("Alter DATABASE NBS_ODSE SET SINGLE_USER WITH ROLLBACK IMMEDIATE")            sqlcmd_execute("RESTORE DATABASE NBS_ODSE FROM DISK ='" + data_dict['DB_RESTORE_PATH'] + i.replace('\n','') + ".bak" + "'" + "WITH REPLACE")            # print(result)        elif "MSGOUTE" in i:            print("Restoring NBS_MSGOUTE")            sqlcmd_execute("Alter DATABASE NBS_MSGOUTE SET SINGLE_USER WITH ROLLBACK IMMEDIATE")            sqlcmd_execute("RESTORE DATABASE NBS_MSGOUTE FROM DISK ='" + data_dict['DB_RESTORE_PATH'] + i.replace('\n', '') + ".bak" + "'" + "WITH REPLACE")            # print(result)        elif "SRTE" in i:            print("Restoring NBS_SRTE")            sqlcmd_execute("Alter DATABASE NBS_SRTE SET SINGLE_USER WITH ROLLBACK IMMEDIATE")            sqlcmd_execute("RESTORE DATABASE NBS_SRTE FROM DISK ='" + data_dict[                'DB_RESTORE_PATH'] + i.replace('\n', '') + ".bak" + "'" + "WITH REPLACE")            # print(result)        elif "RDB" in i:            print("Restoring RDB")            sqlcmd_execute("Alter DATABASE RDB SET SINGLE_USER WITH ROLLBACK IMMEDIATE")            sqlcmd_execute(                "RESTORE DATABASE RDB FROM DISK ='" + data_dict['DB_RESTORE_PATH'] + i.replace('\n','') + ".bak" + "'" + "WITH REPLACE")            # print(result)def update_user_permission():    print("Updating User Permissions on the Databases")    query(        '''        USE nbs_odse;        IF EXISTS (SELECT * FROM sys.database_principals WHERE name = N'nbs_ods') EXEC sp_dropuser 'nbs_ods';        IF EXISTS (SELECT * FROM sys.database_principals WHERE name = N'nbs_rdb') EXEC sp_dropuser 'nbs_rdb';        IF EXISTS (SELECT * FROM sys.database_principals WHERE name = N'nbs_phcmart') EXEC sp_dropuser 'nbs_phcmart';        create user nbs_ods from login nbs_ods;        exec sp_addrolemember 'db_owner', 'nbs_ods';        create user nbs_rdb from login nbs_rdb;        exec sp_addrolemember 'db_datareader', 'nbs_rdb';        create user nbs_phcmart from login nbs_phcmart;        exec sp_addrolemember 'db_datareader', 'nbs_phcmart';        exec sp_addrolemember 'db_datawriter', 'nbs_phcmart';        exec sp_addrolemember 'db_ddladmin', 'nbs_phcmart';                USE nbs_msgoute        IF EXISTS (SELECT * FROM sys.database_principals WHERE name = N'nbs_ods') EXEC sp_dropuser 'nbs_ods';        create user nbs_ods from login nbs_ods;        exec sp_addrolemember 'db_owner', 'nbs_ods';                USE nbs_srte;        IF EXISTS (SELECT * FROM sys.database_principals WHERE name = N'nbs_ods') EXEC sp_dropuser 'nbs_ods';        IF EXISTS (SELECT * FROM sys.database_principals WHERE name = N'srte_admin') EXEC sp_dropuser 'srte_admin';        IF EXISTS (SELECT * FROM sys.database_principals WHERE name = N'nbs_rdb') EXEC sp_dropuser 'nbs_rdb';        IF EXISTS (SELECT * FROM sys.database_principals WHERE name = N'nbs_phcmart') EXEC sp_dropuser 'nbs_phcmart';        create user nbs_ods from login nbs_ods;        exec sp_addrolemember 'db_datareader', 'nbs_ods';        create user srte_admin from login srte_admin;        exec sp_addrolemember 'db_owner', 'srte_admin';        create user nbs_rdb from login nbs_rdb;        exec sp_addrolemember 'db_datareader', 'nbs_rdb';        create user nbs_phcmart from login nbs_phcmart;        exec sp_addrolemember 'db_datareader', 'nbs_phcmart';                USE RDB;        IF EXISTS (SELECT * FROM sys.database_principals WHERE name = N'nbs_ods') EXEC sp_dropuser 'nbs_ods';        IF EXISTS (SELECT * FROM sys.database_principals WHERE name = N'nbs_rdb') EXEC sp_dropuser 'nbs_rdb';        IF EXISTS (SELECT * FROM sys.database_principals WHERE name = N'nbs_phcmart') EXEC sp_dropuser 'nbs_phcmart';        create user nbs_ods from login nbs_ods;        exec sp_addrolemember 'db_datareader', 'nbs_ods';        create user nbs_rdb from login nbs_rdb;        exec sp_addrolemember 'db_owner', 'nbs_rdb';        create user nbs_phcmart from login nbs_phcmart;        exec sp_addrolemember 'db_datareader', 'nbs_phcmart';        exec sp_addrolemember 'db_datawriter', 'nbs_phcmart';        '''    )    # print("Excecuted update permissions query")def query(query):    cur = get_db_connection()    cur.execute(query)    cur.close()def run_upgradesripts():    try:        if data_dict["DATABASEINSTANCE"] == None and data_dict["UPDATE_USER_PERMISSIONS"] == "n":            print("Restoring " + data_dict["DATABASENAME"] + "\\" + data_dict["DATABASEINSTANCE"])        else:            print("Running Upgrade Scripts on " + data_dict["DATABASENAME"])        upgrade_script_path = data_dict["DB_UPGRADE_SCRIPT_PATH"]        print("upgrade_script_path",upgrade_script_path)        all_items = os.listdir(upgrade_script_path)        # print("item",all_items)        for i in all_items:            direct = upgrade_script_path + "\\" + i            print("directory", i)            if (i == "NBS_ODSE"):                extension = ".xsl"                files = [f for f in os.listdir(direct) if                         f.endswith(extension) and os.path.isfile(os.path.join(direct, f))]                for x in files:                    command1 = f'net use t: \\\\{0}\\Temp2 /user:{1} {2}'.format(data_dict["DATABASENAME"],                                                                                 data_dict["SERVER_USERNAME"],                                                                                 data_dict["SERVER_PASSWORD"])                    command_process(command1, True)                    command2 = f'xcopy /S/Y "{direct}\\{x}" "\\\\dev1\\Temp2"'                    command_process(command2, True)                    print("file copied ", files)                    command3 = 'net use g: /delete'                    command_process(command3, True)            files = [f for f in os.listdir(direct) if f.endswith(".sql") and os.path.isfile(os.path.join(direct, f))]            for t in files:                print("Executing file name : ", t)                if data_dict["DATABASEINSTANCE"]:                    strSQLCMDCommands1 = (                        'sqlcmd -m 11 -S {0} -d nbs_odse '                        '-U {1} -P {2} -i "{3}\\{4}\\{5}" '                        '-o "C:\\Temp\\ERRORLOGS.log"'                    ).format(                        data_dict["DATABASENAME"],                        data_dict["DB_USERNAME"],                        data_dict["DB_PASSWORD"],                        data_dict["DB_UPGRADE_SCRIPT_PATH"],                        i,                        t                    )                else:                    strSQLCMDCommands1 = (                        'sqlcmd -m 11 -S {0} -d nbs_odse '                        '-U {1} -P {2} -i "{3}\\{4}\\{5}" '                        '-o "C:\\Temp\\ERRORLOGS.log"'                    ).format(                        data_dict["DATABASENAME"],                        data_dict["DB_USERNAME"],                        data_dict["DB_PASSWORD"],                        data_dict["DB_UPGRADE_SCRIPT_PATH"],                        i,                        t                    )                command_process(strSQLCMDCommands1, True)    except Exception as e:        logger.error(str(e))def update_compatibilitymode():    # execute_query("USE NBS_ODSE")    execute_query("USE master")    execute_query("ALTER DATABASE NBS_MSGOUTE SET COMPATIBILITY_LEVEL = 120")    execute_query("ALTER DATABASE NBS_ODSE SET COMPATIBILITY_LEVEL = 120")    execute_query("ALTER DATABASE NBS_SRTE SET COMPATIBILITY_LEVEL = 120")    execute_query("ALTER DATABASE RDB SET COMPATIBILITY_LEVEL = 120")    print("SQL Server Compatibility Mode has been updated to 120")    execute_query("ALTER DATABASE RDB MODIFY FILE ( NAME = N'RDB', FILEGROWTH = 250000KB )")def update_seedvalue():    rs1 = execute_query("select seed_value_nbr from nbs_odse..Local_UID_generator where type_cd='NBS'")    for i in rs1:        value = i[0]        print(type(value))        if (value < int(2147483648)):            query(                  """                update nbs_odse..Local_UID_generator set seed_value_nbr =  2147483648 where type_cd='NBS';                              update nbs_odse..local_uid_generator set seed_value_nbr = 2147483648 where class_name_cd ='PERSON';                                update nbs_odse..local_uid_generator set seed_value_nbr = 2147483648 where class_name_cd ='public_health_case';                                update nbs_odse..local_uid_generator set seed_value_nbr = 2147483648 where class_name_cd ='CT_CONTACT';                                update nbs_odse..local_uid_generator set seed_value_nbr = 2147483648 where class_name_cd ='INTERVENTION';                                update nbs_odse..local_uid_generator set seed_value_nbr = 2147483648 where class_name_cd ='INTERVIEW';                                update nbs_odse..local_uid_generator set seed_value_nbr = 2147483648 where class_name_cd ='NBS_DOCUMENT';                                update nbs_odse..local_uid_generator set seed_value_nbr = 2147483648 where class_name_cd ='NOTIFICATION';                                update nbs_odse..local_uid_generator set seed_value_nbr = 2147483648 where class_name_cd ='OBSERVATION';                                update nbs_odse..local_uid_generator set seed_value_nbr = 2147483648 where class_name_cd ='ORGANIZATION';                                update nbs_odse..local_uid_generator set seed_value_nbr = 2147483648 where class_name_cd ='PLACE';                                update nbs_odse..local_uid_generator set seed_value_nbr = 2147483648 where class_name_cd ='TREATMENT';                                update nbs_odse..Local_UID_generator set seed_value_nbr =  2147483648 where class_name_cd='AL';                """            )            print("Seed Values in Local_UID_generator have been updated")        else:            print("Seed Values are already big")def version_number():    execute_query("update nbs_odse..nbs_configuration set config_value = '" + data_dict[        "VERSION_NUMBER"] + "' where config_key = 'CODE_BASE'")    print("Version has been updated in nbs_configuration table to " + "'" + data_dict["VERSION_NUMBER"] + "'")if __name__ == "__main__":    print("=====================")    print("data_dictionary",data_dict)    restore = data_dict['RESTORE_DB_BACKUP']    if restore.lower() == 'y':        print("RESTORE_DB_BACKUP")        restore_db_backup()        print("=====================")    permission = data_dict['UPDATE_USER_PERMISSIONS']    if permission.lower() == 'y':        print("UPDATE_USER_PERMISSIONS")        update_user_permission()        print("=====================")    upgrade =   data_dict['RUN_UPGRADESCRIPTS']    if upgrade.lower() == 'y':        print("RUN_UPGRADESCRIPTS")        run_upgradesripts()        print("=====================")    compact = data_dict['UPDATE_COMPATIBILITYMODE']    if compact.lower() =='y':        print("UPDATE_COMPATIBILITYMODE")        update_compatibilitymode()        print("=====================")    seed = data_dict['UPDATE_SEEDVALUE']    if seed.lower() =='y':        print("UPDATE_SEEDVALUE")        update_seedvalue()        print("=====================")    # if data_dict['VERSION_NUMBER_Notused'] != '':    #     print("VERSION_NUMBER_Notused")    #     version_number()    #     print("=====================")